#include <iostream>
#include <cstring>
using namespace std;
int main() {
    int n, id,b,c; 
    string max = ""; 
    string a;
    cin >> n;
	for (int i = 1; i <= n; i++) {
        cin >> a;
        b = a.size();
        c = max.size();
        if (b > c || (b >= c && a > max)) {
            max = a;
            id = i;
        }
    }
    cout << id << "\n" << max << "\n";
    return 0;
}
